+            CommandError::SyntaxError,
+        ),
+        InvalidTrackingCase::InvalidMode { token } => (
+            vec![
+                b"CLIENT".to_vec(),
+                b"TRACKING".to_vec(),
+                sanitize_invalid_mode(token),
+            ],
+            CommandError::SyntaxError,
+        ),
+    }
+}
